function toFeedState(planState: { goal: string; steps: PlanStep[]; startTime: number }): ActivityFeedState {
	const steps: Step[] = planState.steps.map(ps => ({
		label: ps.label,
		completed: ps.completed,
		startTime: undefined,
		endTime: undefined,
		substeps: (ps.detailLines ?? []).map((dl, i) => ({
			label: dl,
			completed: ps.completed,
			startTime: undefined,
			endTime: undefined,
			isReport: false,
		}) as Substep),
	}));
	return {
		goal: planState.goal,
		steps,
		currentStep: planState.steps.findIndex(s => s.active),
		rawText: "",
		planParsed: false,
	};
}
