```typescript
function trimToBudget(lines: string[], budget: number): string[] {
	if (lines.length <= budget) return lines;
	const keepIndices = new Set<number>();
	keepIndices.add(0);  // goal line
	if (lines.length > 1) keepIndices.add(1);  // progress dots
	// Find active step (has a spinner character)
	let activeIdx = -1;
	for (let i = 2; i < lines.length; i++) {
		const trimmed = lines[i].trimStart();
		if (/^[⠋⠙⠹⠸⠼⠴⠦⠧⠇⠏]/.test(trimmed)) {
			activeIdx = i;
			break;
		}
	}
	// Always keep active step and everything after it
	if (activeIdx >= 0) {
		for (let i = activeIdx; i < lines.length; i++) {
			keepIndices.add(i);
		}
	}
	// ... trim oldest rows from top before activeIdx ...
}
```

