## 5. Tool Definition Pattern (pi.registerTool())

```typescript
import { Type } from "typebox";
import { StringEnum } from "@earendil-works/pi-ai";

pi.registerTool({
  name: "my_tool",
  label: "My Tool",
  description: "What this tool does",
  promptSnippet: "One-line entry in Available tools",
  promptGuidelines: ["Use my_tool when..."],
  parameters: Type.Object({
    action: StringEnum(["list", "add"] as const),
    text: Type.Optional(Type.String()),
  }),
  prepareArguments(args) {
    // Optional compatibility shim before schema validation
    return args;
  },
  async execute(toolCallId, params, signal, onUpdate, ctx) {
    // signal?.aborted — check for cancellation
    // onUpdate?.({ content: [...], details: { progress: 50 } }) — stream progress

    return {
      content: [{ type: "text", text: "Done" }],  // Sent to LLM
      details: { data: result },                   // For rendering & state
      terminate: true,  // Optional: skip auto follow-up LLM call
    };
  },
  // Optional custom TUI rendering:
  renderCall(args, theme, context) { /* return Component */ },
  renderResult(result, options, theme, context) { /* return Component */ },
});
```

### Signaling errors
```typescript
// CORRECT — throw to signal error (sets isError: true, reported to LLM)
async execute(toolCallId, params) {
  if (!isValid(params)) {
    throw new Error(`Invalid input: ${params}`);
  }
  return { content: [{ type: "text", text: "OK" }], details: {} };
}

// WRONG — returning never sets isError regardless of properties
```

### onUpdate callback contract
```typescript
// Called during execute() to stream progress
onUpdate?.({ 
  content: [{ type: "text", text: "Working..." }],
  details: { progress: 50 },
});
```

