export default function shellExtension(pi: ExtensionAPI) {
  pi.on('tool_call', async (event) => {
    for (const blockedTool of blockedTools) {
      if (event.toolName !== blockedTool.toolName) continue
      return { block: true, reason: blockedTool.reason }
    }
    if (event.toolName !== 'bash') return
    const command = getBashCommand(event.input)
    if (!command)
      return {
        block: true,
        reason: 'The `bash` tool was called without a command.',
      }
    const segmentResult = splitCommand(command)
    if (segmentResult.reason)
      return {
        block: true,
        reason: segmentResult.reason,
      }
    const segments = segmentResult.segments ?? []
    for (const segment of segments) {
      const tokens = tokenizeCommand(segment)
      if (!tokens)
        return {
          block: true,
          reason: 'Unterminated quotes are blocked in the `bash` tool.',
        }
      const reason = getForbiddenReason(tokens)
      if (!reason) continue
      return { block: true, reason }
    }
  })
}
```

**Handler logic summary:**
1. First checks `blockedTools` (grep/find/ls) — blocks those PI tools with redirect message
2. If not a blocked tool AND not `bash` — returns undefined (allows other tools through)
3. If `bash` — extracts command string from `event.input`
4. Passes through validation pipeline:
   - `splitCommand()` → blocks backticks, `$()`, variable expansion, `<`/`>` redirection, `()`, `&`, `;`, newlines, unterminated quotes, pipes
   - Each pipe-separated segment → `tokenizeCommand()` → handles quoting/unterminated quotes
   - Each token list → `getForbiddenReason()` → checks shell keywords, command runners, `sed -i`, then iterates `forbiddenRules` with pattern matching
5. First violation found → `{ block: true, reason }`; no violations → returns `undefined` (allows)

